def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a phrase
    def phrase(subj: str, pred: str, obj: str, include_subject: bool = True) -> str:
        """
        Convert a single predicate/object pair into a phrase.
        If include_subject is False, the phrase is written as a continuation
        that can be attached to a previous clause about the same subject.
        """
        obj = obj.strip('"')
        p = pred.lower()

        # Helper to optionally prepend the subject
        def fmt(text: str) -> str:
            return f"{subj} {text}" if include_subject else text

        if p == "birthdate":
            return fmt(f"was born on {obj}")
        if p == "birthplace":
            return fmt(f"was born in {obj}")
        if p == "deathdate":
            return fmt(f"died on {obj}")
        if p == "deathplace":
            return fmt(f"died in {obj}")
            if p == "nationality":
                # Use a simple wording that works for any country name
                return fmt(f"is a citizen of {obj}")
            if p == "leader":
                return fmt(f"is led by {obj}")
            if p == "occupation":
                return fmt(f"is a {obj}")
            if p == "status":
                # Status like "Retired" – make it an adjective before the name when possible
                if include_subject:
                    return f"{obj} {subj}"
                else:
                    return f"is {obj.lower()}"
            if p == "selectedbynasa":
                return fmt(f"was selected by NASA in {obj}")
            if p == "mission":
                return fmt(f"was a crew member of {obj}")
            if p == "timeinspace":
                return fmt(f"spent {obj} minutes in space")
            if p == "title":
                return fmt(f"held the title of {obj}")
            if p == "award":
                return fmt(f"received the {obj}")
            if p == "awards":
                return fmt(f"received {obj} awards")
            if p == "ribbonaward":
                return fmt(f"was awarded the {obj}")
            if p == "operator":
                return fmt(f"was operated by {obj}")
            if p == "commander":
                return fmt(f"was commanded by {obj}")
            if p == "backuppilot":
                return fmt(f"was the backup pilot on {obj}")
            if p == "crewmembers":
                return fmt(f"had crew member {obj}")
            # Fallback
            return fmt(f"{pred} {obj}")

        # Build clauses in order, omitting repeated subject
        clauses = []
        prev_subj = None
        for t in triples:
            include_subj = (t.subject != prev_subj)
            clauses.append(phrase(t.subject, t.predicate, t.object, include_subject=include_subj))
            prev_subj = t.subject

        if not clauses:
            return ""
        if len(clauses) == 1:
            return clauses[0] + "."
        else:
            return ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."

    # Group triples by subject to build compact sentences
    from collections import defaultdict
    subj_groups = defaultdict(list)
    for t in triples:
        subj_groups[t.subject].append(t)

    sentences = []
    for subj, group in subj_groups.items():
        # Sort predicates to place status first (as adjective) when present
        group = sorted(group, key=lambda x: 0 if x.predicate.lower() == "status" else 1)
        parts = []
        for i, t in enumerate(group):
            include_subj = (i == 0)  # only the first clause includes the subject
            parts.append(phrase(t.subject, t.predicate, t.object, include_subject=include_subj))
        # Join parts with commas and a final "and"
        if len(parts) == 1:
            sentence = parts[0] + "."
        else:
            sentence = ", ".join(parts[:-1]) + ", and " + parts[-1] + "."
        sentences.append(sentence)

    # Combine sentences for different subjects
    return " ".join(sentences)

    # Build a flat list of clause strings in the order of input triples
    clauses = [phrase(t.subject, t.predicate, t.object) for t in triples]

    # Join clauses into a single fluent sentence
    if not clauses:
        return ""
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."

    return sentence

